<content>import { describe, it, expect, vi } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { BrowserRouter } from 'react-router-dom';
import { SidebarItem } from '../SidebarItem';
import { NavigationIconE } from 'Types/NavigationIconE';
import { SidebarItemT } from 'Types/SidebarItemT';

const mockNavigate = vi.fn();

vi.mock('react-router-dom', async () => {
  const actual = await vi.importActual('react-router-dom');
  return {
    ...actual,
    useNavigate: () => mockNavigate,
  };
});

const createMockItem = (overrides?: Partial<SidebarItemT>): SidebarItemT => ({
  id: 'test-item',
  label: 'Test Item',
  icon: NavigationIconE.Dashboard,
  path: '/test',
  isActive: false,
  ...overrides,
});

const renderSidebarItem = (item: SidebarItemT, onItemClick?: (itemId: string) => void) => {
  return render(
    <BrowserRouter>
      <SidebarItem item={item} onItemClick={onItemClick} />
    </BrowserRouter>,
  );
};

describe('SidebarItem', () => {
  it('renders with correct label', () => {
    const item = createMockItem({ label: 'Dashboard' });
    renderSidebarItem(item);

    expect(screen.getByText('Dashboard')).toBeInTheDocument();
  });

  it('renders with correct icon', () => {
    const item = createMockItem({ icon: NavigationIconE.Budget });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    const icon = button.querySelector('[data-icon]');
    expect(icon).toHaveAttribute('data-icon', 'budget');
  });

  it('applies active class when item is active', () => {
    const item = createMockItem({ isActive: true });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    expect(button).toHaveClass('active');
  });

  it('does not apply active class when item is inactive', () => {
    const item = createMockItem({ isActive: false });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    expect(button).not.toHaveClass('active');
  });

  it('sets aria-current when item is active', () => {
    const item = createMockItem({ isActive: true });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    expect(button).toHaveAttribute('aria-current', 'page');
  });

  it('does not set aria-current when item is inactive', () => {
    const item = createMockItem({ isActive: false });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    expect(button).not.toHaveAttribute('aria-current');
  });

  it('navigates to correct path when clicked', () => {
    const item = createMockItem({ path: '/dashboard' });
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    fireEvent.click(button);

    expect(mockNavigate).toHaveBeenCalledWith('/dashboard');
  });

  it('calls onItemClick callback when provided', () => {
    const onItemClick = vi.fn();
    const item = createMockItem({ id: 'test-id' });
    renderSidebarItem(item, onItemClick);

    const button = screen.getByRole('button');
    fireEvent.click(button);

    expect(onItemClick).toHaveBeenCalledWith('test-id');
  });

  it('does not throw error when onItemClick is not provided', () => {
    const item = createMockItem();
    renderSidebarItem(item);

    const button = screen.getByRole('button');
    expect(() => fireEvent.click(button)).not.toThrow();
  });

  it('renders all navigation icon types correctly', () => {
    const icons = [
      NavigationIconE.Dashboard,
      NavigationIconE.Budget,
      NavigationIconE.Transactions,
      NavigationIconE.Reports,
      NavigationIconE.Settings,
      NavigationIconE.Help,
    ];

    icons.forEach((icon) => {
      const { unmount } = renderSidebarItem(createMockItem({ icon }));
      const button = screen.getByRole('button');
      const iconElement = button.querySelector('[data-icon]');
      expect(iconElement).toHaveAttribute('data-icon', icon);
      unmount();
    });
  });

  it('has accessible button with aria-label', () => {
    const item = createMockItem({ label: 'Dashboard' });
    renderSidebarItem(item);

    const button = screen.getByRole('button', { name: 'Dashboard' });
    expect(button).toBeInTheDocument();
  });
});
